import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "How many days are in a year?", a: "A regular year has 365 days. A leap year, which occurs every 4 years (with some exceptions), has 366 days. When counting days across years, this calculator accounts for leap years automatically." },
  { q: "Does the day counter include both start and end dates?", a: "By default, the count includes the start date but not the end date (exclusive end). If you want to include both days, add 1 to the result. Toggle 'include end date' to change this behavior." },
  { q: "How do I count business days only?", a: "Business days exclude weekends (Saturday and Sunday). Use the 'business days only' mode in this calculator to exclude weekends from the count. It does not account for public holidays." },
  { q: "What is the difference between a day counter and a date calculator?", a: "A day counter tells you how many days are between two dates. A date calculator lets you add or subtract days from a date to find a future or past date." },
  { q: "How many business days are in a month?", a: "Most months have 20-23 business days. January typically has 23 business days, February has 19-20. The exact count depends on which day of the week the month starts and any holidays in your jurisdiction." },
  { q: "How do I calculate how many days until an event?", a: "Set the start date to today and the end date to the event date. The calculator will show exactly how many days remain. Check the 'include end date' box if you want to count the event day itself." },
  { q: "What is the longest possible streak of business days without a weekend?", a: "Five consecutive business days (Monday through Friday) is the maximum before a weekend interrupts. Some holiday-heavy weeks in the US have only 3-4 business days." },
];

function toMidnight(d: Date) { return new Date(d.getFullYear(), d.getMonth(), d.getDate()); }

export default function DayCounter() {
  const today = new Date();
  const pad = (n: number) => String(n).padStart(2, "0");
  const fmt = (d: Date) => `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
  const futureDate = new Date(today); futureDate.setDate(today.getDate() + 30);

  const [start, setStart] = useState(fmt(today));
  const [end, setEnd] = useState(fmt(futureDate));
  const [includeEnd, setIncludeEnd] = useState(false);
  const [businessOnly, setBusinessOnly] = useState(false);

  const s = toMidnight(new Date(start + "T00:00:00"));
  const e = toMidnight(new Date(end + "T00:00:00"));
  const diffMs = e.getTime() - s.getTime();
  const valid = diffMs >= 0 && !isNaN(diffMs);
  const totalDays = Math.round(diffMs / 86400000) + (includeEnd ? 1 : 0);

  let businessDays = 0;
  if (valid && businessOnly) {
    const cur = new Date(s); const endD = new Date(e);
    if (includeEnd) endD.setDate(endD.getDate() + 1);
    while (cur < endD) {
      const day = cur.getDay();
      if (day !== 0 && day !== 6) businessDays++;
      cur.setDate(cur.getDate() + 1);
    }
  }

  const displayDays = businessOnly ? businessDays : totalDays;

  return (
    <>
      <SEOHead
        title="Free Day Counter Online - Count Calendar and Business Days Between Dates Instantly | CalcHive"
        description="Free online day counter. Count the exact number of calendar or business days between any two dates instantly. 100% free for everyone, no signup required, works on all devices."
        canonical="/day-counter"
        keywords="free day counter, days between dates counter free online, business days calculator free, calendar days counter free, count days between dates free"
        category="Date & Time Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-orange-600 dark:text-orange-400 bg-orange-50 dark:bg-orange-950/50 px-3 py-1 rounded-full mb-4 inline-block">Date &amp; Time</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Day Counter Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free day counter to count days between dates free as calendar days or business days. This days between dates counter free online also works as a business days calculator free and calendar days counter free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 mb-6">
            <div>
              <label className="text-sm font-semibold text-foreground mb-2 block">Start Date</label>
              <input type="date" value={start} onChange={e => setStart(e.target.value)} className="w-full px-4 py-3 rounded-xl border border-border bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 text-sm" />
            </div>
            <div>
              <label className="text-sm font-semibold text-foreground mb-2 block">End Date</label>
              <input type="date" value={end} onChange={e => setEnd(e.target.value)} className="w-full px-4 py-3 rounded-xl border border-border bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 text-sm" />
            </div>
          </div>
          <div className="flex flex-wrap gap-4 mb-6">
            {[{ label: "Include end date", val: includeEnd, set: setIncludeEnd }, { label: "Business days only", val: businessOnly, set: setBusinessOnly }].map(({ label, val, set }) => (
              <label key={label} className="flex items-center gap-2 cursor-pointer text-sm text-foreground">
                <input type="checkbox" checked={val} onChange={e => set(e.target.checked)} className="w-4 h-4 rounded" />
                {label}
              </label>
            ))}
          </div>
          <motion.div key={`${start}-${end}-${includeEnd}-${businessOnly}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            {!valid ? (
              <div className="bg-red-50 dark:bg-red-950/50 border border-red-200 dark:border-red-800 rounded-2xl p-6 text-center">
                <p className="text-red-600 dark:text-red-400 font-semibold">End date must be after start date</p>
              </div>
            ) : (
              <>
                <div className="bg-gradient-to-br from-orange-500 to-orange-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
                  <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{businessOnly ? "Business Days" : "Calendar Days"}</p>
                  <p className="text-7xl font-black text-white tracking-tight" data-testid="result-days">{displayDays.toLocaleString()}</p>
                  <p className="text-white/70 text-sm mt-1">days between dates</p>
                </div>
                <div className="grid grid-cols-3 gap-3">
                  {[{ label: "Weeks", value: Math.floor(totalDays / 7) }, { label: "Months (approx)", value: (totalDays / 30.44).toFixed(1) }, { label: "Years (approx)", value: (totalDays / 365.25).toFixed(2) }].map(({ label, value }) => (
                    <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                      <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                      <p className="text-lg font-extrabold text-foreground">{value}</p>
                    </div>
                  ))}
                </div>
              </>
            )}
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Count Days Between Two Dates for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Day counting is based on the difference between two dates measured in milliseconds, then converted to days. The choice between inclusive and exclusive end date matters for legal and contractual calculations.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Days = (End Date - Start Date) in ms  x  86,400,000</p>
            <p className="text-xs text-muted-foreground mt-2">Business days: iterates each day, skips Saturday (day 6) and Sunday (day 0)</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Count Business Days vs Calendar Days</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Month", "Calendar Days", "Typical Business Days", "Notes"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["January", "31", "22-23", "New Year's Day reduces by 1"],
                  ["February", "28-29", "19-20", "Shortest month; leap year adds 1 day"],
                  ["March", "31", "21-23", "No federal holidays"],
                  ["April", "30", "21-22", "No federal holidays"],
                  ["May", "31", "21-22", "Memorial Day reduces by 1"],
                  ["June", "30", "21-22", "Juneteenth (June 19) reduces by 1"],
                  ["July", "31", "21-22", "July 4th reduces by 1"],
                  ["August", "31", "22-23", "No federal holidays"],
                  ["September", "30", "20-22", "Labor Day reduces by 1"],
                  ["October", "31", "22-23", "Columbus Day (observed)"],
                  ["November", "30", "19-21", "Thanksgiving + Veterans Day"],
                  ["December", "31", "21-22", "Christmas Day reduces by 1"],
                ].map(([month, cal, biz, notes]) => (
                  <tr key={month} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{month}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{cal}</td>
                    <td className="py-2.5 px-4 text-orange-600 dark:text-orange-400 font-medium">{biz}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{notes}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Date Day Counter for Everyone</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free date and time tool on any device to compare schedules, track durations, and get instant results without signup.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/day-counter" headingLevel="h3" />
      </main>
    </>
  );
}


